#!/usr/bin/env node
/**
 * Heritage corpus triage: direct Mathlib imports, umbrella closure from `ForkRaceFoldTheorems.lean`,
 * and a histogram of imported Mathlib module strings.
 *
 * Run from `open-source/gnosis`: `node scripts/report-mathlib-import-fan-in.mjs`
 * Output: Markdown on stdout (redirect to file in CI if needed).
 */
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const pkgRoot = path.resolve(__dirname, '..');
const leanLean = path.join(pkgRoot, 'lean', 'Lean');

const UMBRELLA = 'ForkRaceFoldTheorems.lean';

function listLeanFiles(dir, acc = []) {
  for (const name of fs.readdirSync(dir, { withFileTypes: true })) {
    const p = path.join(dir, name.name);
    if (name.isDirectory()) listLeanFiles(p, acc);
    else if (name.name.endsWith('.lean')) acc.push(p);
  }
  return acc;
}

function moduleNameToPath(mod) {
  const parts = mod.split('.');
  return path.join(leanLean, ...parts) + '.lean';
}

function parseImports(text) {
  const out = [];
  for (const line of text.split('\n')) {
    const t = line.trim();
    const m = t.match(/^import\s+(\S+)/);
    if (m) out.push(m[1]);
  }
  return out;
}

function isStdish(imp) {
  return imp === 'Init' || imp.startsWith('Std');
}

function isMathlib(imp) {
  return imp === 'Mathlib' || imp.startsWith('Mathlib.');
}

function buildForwardGraph(allFiles) {
  /** @type {Map<string, string[]>} */
  const g = new Map();
  for (const f of allFiles) {
    const text = fs.readFileSync(f, 'utf8');
    const imps = parseImports(text);
    const edges = [];
    for (const imp of imps) {
      if (isStdish(imp) || isMathlib(imp)) continue;
      const target = moduleNameToPath(imp);
      if (fs.existsSync(target)) edges.push(target);
    }
    g.set(f, edges);
  }
  return g;
}

function bfsReachable(g, entry) {
  const seen = new Set();
  const q = [entry];
  while (q.length) {
    const u = q.shift();
    if (seen.has(u)) continue;
    seen.add(u);
    for (const v of g.get(u) ?? []) {
      if (!seen.has(v)) q.push(v);
    }
  }
  return seen;
}

function main() {
  const allFiles = listLeanFiles(leanLean);
  const g = buildForwardGraph(allFiles);

  const umbrellaPath = path.join(leanLean, UMBRELLA);
  if (!fs.existsSync(umbrellaPath)) {
    console.error(`report-mathlib-import-fan-in: missing ${UMBRELLA}`);
    process.exit(2);
  }
  const reachable = bfsReachable(g, umbrellaPath);

  /** @type {Map<string, number>} */
  const mathlibModuleHistogram = new Map();
  /** @type {Array<{ file: string, line: string }>} */
  const directMathlibLines = [];

  for (const f of allFiles) {
    const rel = path.relative(pkgRoot, f);
    const text = fs.readFileSync(f, 'utf8');
    for (const line of text.split('\n')) {
      const t = line.trim();
      if (t.startsWith('import Mathlib') || /^import\s+Mathlib\./.test(t)) {
        directMathlibLines.push({ file: rel, abs: f, line: t });
        const m = t.match(/^import\s+(\S+)/);
        if (m) {
          const mod = m[1];
          mathlibModuleHistogram.set(mod, (mathlibModuleHistogram.get(mod) ?? 0) + 1);
        }
      }
    }
  }

  const inUmbrella = directMathlibLines.filter(({ abs }) => reachable.has(abs));

  const histSorted = [...mathlibModuleHistogram.entries()].sort((a, b) => b[1] - a[1]);

  console.log('# Mathlib import triage (heritage `lean/Lean`)');
  console.log('');
  console.log(`- Workspace root: \`${path.relative(process.cwd(), pkgRoot) || '.'}\``);
  console.log(`- Lean sources: \`lean/Lean\` (${allFiles.length} \`.lean\` files)`);
  console.log(`- Umbrella for reachability: \`${UMBRELLA}\` (${reachable.size} files in forward import closure, project-local imports only)`);
  console.log('');
  console.log('## Direct Mathlib imports (entire tree)');
  console.log('');
  console.log(`| Count |`);
  console.log(`|------:|`);
  console.log(`| ${directMathlibLines.length} |`);
  console.log('');
  console.log('## Mathlib module histogram (direct `import` lines, entire tree)');
  console.log('');
  console.log('| Module | Files |');
  console.log('|--------|------:|');
  for (const [mod, c] of histSorted.slice(0, 80)) {
    console.log(`| \`${mod}\` | ${c} |`);
  }
  if (histSorted.length > 80) console.log(`| … | (${histSorted.length - 80} more rows) |`);
  console.log('');
  console.log('## Direct Mathlib imports reachable from umbrella (project-local BFS)');
  console.log('');
  console.log(`| Count |`);
  console.log(`|------:|`);
  console.log(`| ${inUmbrella.length} |`);
  console.log('');
  console.log('| File | Import |');
  console.log('|------|--------|');
  for (const { file, line } of inUmbrella.slice(0, 200)) {
    const m = line.match(/^import\s+(\S+)/);
    const mod = m ? m[1] : line;
    console.log(`| \`${file}\` | \`${mod}\` |`);
  }
  if (inUmbrella.length > 200) console.log(`| … | (${inUmbrella.length - 200} more rows) |`);
  console.log('');
  console.log('## Notes');
  console.log('');
  console.log('- Reachability ignores `import Mathlib` edges by design (same as Init-only closure tooling).');
  console.log('- Fan-in to the umbrella is approximated by “in umbrella closure **and** imports Mathlib”.');
  console.log('- For dependency peeling, pair this report with `scripts/validate-init-only-import-closure.mjs`.');
}

main();
